class Solution:
    def minExtraChar(self, s: str, dictionary: List[str]) -> int:
        my_set = set(dictionary)

        @cache
        def dfs(index):
            result = len(s) - index

            for i in range(index, len(s)):
                for j in range(i, len(s)):
                    current = s[i:j + 1]
                    if current in my_set:
                        result = min(result, i - index + dfs(j + 1))
            return result

        return dfs(0)
